SELECT
*
FROM t_asset_requisition_revert

    type = #{queryForm.type}


        and DATE_FORMAT(use_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(use_time, '%Y-%m-%d') <= #{queryForm.endTime}



        AND ( INSTR(requisition_revert_no,#{queryForm.keywords})
        OR INSTR(create_user_name,#{queryForm.keywords})
        )


        AND enterprise_id = #{queryForm.enterpriseId}


        AND department_id = #{queryForm.departmentId}



    ORDER BY create_time DESC
